mapper.select:
select
id, runtime,scriptname,threads,url,sample, samples,errors, error_1, errors_1, error_2,
errors_2, error_3, errors_3, error_4, errors_4, error_5,errors_5
from jmeter_interface_top5_errors
where   runtime = #{lastruntime,jdbcType=VARCHAR} and scriptname = #{scriptname,jdbcType=VARCHAR}
and sample = #{transactionName,jdbcType=VARCHAR}
